// Parse and validate the AI JSON output against the alert_classification schema.
// Falls back gracefully when the AI returns malformed output.
const item = $input.item.json;
const rawContent = item?.message?.content || item?.choices?.[0]?.message?.content || '';

const VALID_TOPICS = ['crypto', 'finance', 'economy', 'health', 'ai', 'energy', 'technology'];

let ai;
try {
  // Strip potential markdown code fences
  const cleaned = rawContent.replace(/^```[a-z]*\n?|\n?```$/g, '').trim();
  ai = JSON.parse(cleaned);
} catch (e) {
  // Parsing failed — return a low-confidence fallback
  ai = {
    topic_slug: $('Expand Items').item.json.topic_candidates?.[0] || 'technology',
    secondary_topics: [],
    headline: $('Expand Items').item.json.headline,
    summary_text: $('Expand Items').item.json.body?.slice(0, 500) || $('Expand Items').item.json.headline,
    severity_score: 0,
    importance_score: 0,
    confidence_score: 0,
    send_alert: false,
    alert_reason: 'AI output parse failure — skipping alert.',
    cluster_label: null
  };
}

// Validate required fields
if (!VALID_TOPICS.includes(ai.topic_slug)) {
  ai.topic_slug = $('Expand Items').item.json.topic_candidates?.[0] || 'technology';
}
if (typeof ai.severity_score  !== 'number') ai.severity_score  = 0;
if (typeof ai.importance_score !== 'number') ai.importance_score = 0;
if (typeof ai.confidence_score !== 'number') ai.confidence_score = 0;
if (typeof ai.send_alert !== 'boolean') ai.send_alert = false;

const source = $('Expand Items').item.json;

return [{
  json: {
    item_id:          source.item_id,
    topic_slug:       ai.topic_slug,
    secondary_topics: Array.isArray(ai.secondary_topics) ? ai.secondary_topics.filter(t => VALID_TOPICS.includes(t)).slice(0, 2) : [],
    headline:         (ai.headline || source.headline || '').slice(0, 250),
    summary_text:     (ai.summary_text || '').slice(0, 500),
    source_url:       source.source_url || null,
    source_name:      source.source_name,
    severity_score:   Math.min(100, Math.max(0, Math.round(ai.severity_score))),
    importance_score: Math.min(100, Math.max(0, Math.round(ai.importance_score))),
    confidence_score: Math.min(100, Math.max(0, Math.round(ai.confidence_score))),
    send_alert:       ai.send_alert === true,
    alert_reason:     ai.alert_reason || null,
    event_at:         source.published_at,
    cluster_label:    ai.cluster_label || source.cluster_label || null
  }
}];

// Collect all classified alerts and return them as the workflow output.
const items = $input.all().map(i => i.json);
return [{ json: { items } }];
